    90→          }
    91→        };
    92→      } catch (error) {
    93→        if ((error as Error).name === 'ExamNotFoundError') {
    94→          return reply.code(404).send({
    95→            success: false,
    96→            error: 'Exam not found'
    97→          });
    98→        }
    99→
   100→        if ((error as Error).name === 'NotEnrolledError') {
   101→          return reply.code(403).send({
