   103→            error: 'You are not enrolled in this exam'
   104→          });
   105→        }
   106→
   107→        if ((error as Error).name === 'CapacityExceededError') {
   108→          return reply.code(429).send({
   109→            success: false,
   110→            error: (error as Error).message
   111→          });
   112→        }
   113→
   114→        if ((error as Error).name === 'RoomCollisionError') {
   115→          return reply.code(500).send({
   116→            success: false,
   117→            error: 'Failed to generate unique room code. Please try again.'
   118→          });
   119→        }
   120→
   121→        throw error;
   122→      }
   123→    }
