   148→          success: true,
   149→          data: {
   150→            roomId: room.id,
   151→            examName: room.exam_name,
   152→            courseName: room.course_name,
   153→            status: room.status
   154→          }
   155→        };
   156→      } catch (error) {
   157→        if ((error as Error).name === 'RoomNotFoundError') {
   158→          return reply.code(404).send({
   159→            success: false,
   160→            error: 'Invalid invite link'
   161→          });
   162→        }
   163→
   164→        throw error;
