   169→  // ==========================================================================
   170→  // POST /api/room/:code/validate-token - Validate JWT token and return room info
   171→  // ==========================================================================
   172→  // NOTE: No authentication required - the JWT token IS the authentication
   173→
   174→  fastify.post('/api/room/:code/validate-token', {
   175→    schema: {
   176→      params: {
   177→        type: 'object',
   178→        properties: {
   179→          code: { type: 'string' }
   180→        },
   181→        required: ['code']
   182→      },
   183→      body: {
   184→        type: 'object',
   185→        properties: {
   186→          token: { type: 'string' }
   187→        },
   188→        required: ['token']
   189→      }
   190→    },
   191→    handler: async (request, reply) => {
   192→    const { code } = request.params as { code: string };
   193→    const { token } = request.body as { token: string };
   194→
   195→    try {
   196→      // Verify JWT token using Fastify's JWT plugin
   197→      const decoded = fastify.jwt.verify(token) as any;
   198→
   199→      // Check if token matches this room (case-insensitive)
   200→      if (decoded.roomCode?.toUpperCase() !== code.toUpperCase()) {
   201→        return reply.code(403).send({
   202→          success: false,
   203→          error: 'Token does not match this room'
   204→        });
   205→      }
   206→
   207→      // Check if token is expired (jwt.verify should handle this, but double-check)
   208→      if (decoded.exp && decoded.exp < Date.now() / 1000) {
   209→        return reply.code(403).send({
   210→          success: false,
   211→          error: 'Token has expired'
   212→        });
   213→      }
   214→
   215→      // Get room info with current enrollment count
   216→      const roomResult = await fastify.pg.query(
   217→        `SELECT r.id, r.room_code, r.capacity, r.status,
   218→                COUNT(e.id) as current_enrolled
   219→         FROM proctoring_rooms r
   220→         LEFT JOIN room_enrollments e ON e.room_id = r.id
   221→         WHERE r.room_code = $1
   222→         GROUP BY r.id`,
   223→        [code.toUpperCase()]
   224→      );
   225→
   226→      if (roomResult.rows.length === 0) {
   227→        return reply.code(404).send({
   228→          success: false,
   229→          error: 'Room not found'
   230→        });
   231→      }
   232→
   233→      const room = roomResult.rows[0];
   234→
   235→      // Check if room is active
   236→      if (room.status !== 'activated') {
   237→        return reply.code(400).send({
   238→          success: false,
   239→          error: 'Room is not active'
   240→        });
   241→      }
   242→
   243→      // Check capacity (prevent over-enrollment at validation stage)
   244→      const currentEnrolled = parseInt(room.current_enrolled) || 0;
   245→      if (currentEnrolled >= room.capacity) {
   246→        return reply.code(429).send({
   247→          success: false,
   248→          error: `Room is full (${currentEnrolled}/${room.capacity} students enrolled)`
   249→        });
   250→      }
   251→
   252→      return reply.send({
   253→        success: true,
   254→        data: {
   255→          roomId: room.id,
   256→          roomCode: room.room_code,
   257→          capacity: room.capacity,
   258→          currentEnrolled: currentEnrolled,
   259→          userId: decoded.userId
   260→        }
   261→      });
   262→
   263→    } catch (error) {
   264→      const errorObj = error as any;
   265→
   266→      if (errorObj.name === 'JsonWebTokenError' || errorObj.code === 'FAST_JWT_NO_ACTIVE') {
   267→        return reply.code(403).send({
   268→          success: false,
   269→          error: 'Invalid token'
   270→        });
   271→      }
   272→
   273→      if (errorObj.name === 'TokenExpiredError') {
   274→        return reply.code(403).send({
   275→          success: false,
   276→          error: 'Token has expired'
   277→        });
   278→      }
   279→
   280→      throw error;
   281→    }
   282→  }
   283→});
