   344→            roomCode: room.room_code,
   345→            examName: room.exam_name,
   346→            courseName: room.course_name,
   347→            status: room.status,
   348→            enrollmentSignature // Include signature for validation
   349→          }
   350→        };
   351→      } catch (error) {
   352→        const errorObj = error as any;
   353→
   354→        // Handle specific error types with clear messages
   355→        if (errorObj.name === 'RoomNotFoundError') {
   356→          return reply.code(404).send({
   357→            success: false,
