   390→          fastify.log.error({ error }, 'Database connection failed during student join');
   391→          return reply.code(503).send({
   392→            success: false,
   393→            error: 'Unable to connect to the database. Please try again in a moment.'
   394→          });
   395→        }
   396→
   397→        // Generic error handler (catches all other errors)
