   196→
   197→  /**
   198→   * Generate a random 8-character uppercase invite code
   199→   * Uses digits plus uppercase letters to keep the code easy to type and read
   200→   * Uses cryptographically secure random bytes
   201→   */
   202→  private generateRoomCode(): string {
   203→    const chars = '0123456789ABCDEFGHJKLMNPQRSTUVWXYZ';
   204→    // Generate 8 random bytes and convert to a human-friendly uppercase code
   205→    const bytes = randomBytes(8);
   206→    let code = '';
   207→    for (let i = 0; i < 8; i++) {
