   243→    // 3. Check capacity (count enrolled students for this exam)
   244→    const capacityResult = await this.pg.query<{ count: string }>(
   245→      `SELECT COUNT(DISTINCT ea.user_id) as count
   246→       FROM exam_attempts ea
   247→       WHERE ea.exam_id = $1
   248→       AND ea.status IN ('in_progress', 'submitted')`,
   249→      [examId]
   250→    );
   251→
   252→    const enrolledCount = parseInt(capacityResult.rows[0].count, 10);
   253→    const capacity = 15; // Default capacity from design
   254→
   255→    if (enrolledCount >= capacity) {
   256→      throw new CapacityExceededError(enrolledCount, capacity);
   257→    }
   258→
   259→    // 4. Generate unique room code (retry 3x on collision)
   260→    let roomCode: string = '';
   261→    let attempts = 0;
   262→    const maxAttempts = 3;
   263→
   264→    while (attempts < maxAttempts) {
   265→      roomCode = this.generateRoomCode();
