   273→      if (existingResult.rows.length === 0) {
   274→        // Code is unique, use it
   275→        break;
   276→      }
   277→
   278→      attempts++;
   279→    }
   280→
   281→    if (attempts >= maxAttempts) {
   282→      throw new RoomCollisionError();
   283→    }
   284→
   285→    // 5. Insert room
   286→    const insertResult = await this.pg.query<Room>(
   287→      `INSERT INTO proctoring_rooms (exam_id, teacher_id, room_code, status, capacity)
   288→       VALUES ($1, $2, $3, 'created', $4)
