// ============================================================================
// Authentication Middleware
// Validates JWT tokens and protects routes
// ============================================================================

import { FastifyRequest, FastifyReply } from 'fastify';
import jwtService from '../modules/auth/jwt.service';
import authService from '../modules/auth/auth.service';
import logger from '../config/logger';
import { UnauthorizedError } from '../utils/errors';
import {
  getManualAuthUser,
  isManualProctoringRequest,
  validateManualSessionFromRequest
} from '../modules/manual-proctoring/manual-proctoring.compat';
import {
  getRoomEnrollmentContext,
  hasRoomEnrollmentHeaders,
  isValidRoomEnrollmentHeaders
} from '../modules/room/room-enrollment.service';

// ============================================================================
// Auth Middleware
// ============================================================================

/**
 * Authentication middleware
 * Validates JWT token and attaches user to request
 */
export async function authMiddleware(
  request: FastifyRequest,
  reply: FastifyReply
): Promise<void> {
  try {
    const headers = request.headers as Record<string, unknown>;

    if (hasRoomEnrollmentHeaders(headers)) {
      if (!isValidRoomEnrollmentHeaders(headers)) {
        await reply.code(403).send({
          success: false,
          error: 'Invalid enrollment signature. Please rejoin the room.'
        });
        return;
      }

      const roomEnrollment = await getRoomEnrollmentContext(request.server.pg as any, headers);

      if (!roomEnrollment) {
        await reply.code(401).send({
          success: false,
          error: 'Room enrollment not found. Please rejoin the room.'
        });
        return;
      }

      (request as any).user = roomEnrollment.user;
      (request as any).roomEnrollment = roomEnrollment;
      (request as any).tokenPayload = {
        userId: roomEnrollment.user.id,
        username: roomEnrollment.user.username,
        email: roomEnrollment.user.email,
        role: roomEnrollment.user.role,
        exp: Math.floor(Date.now() / 1000) + 3600
      };
      return;
    }

    if (isManualProctoringRequest(request as any)) {
      const manualSessionResult = validateManualSessionFromRequest(request as any);

      if (!manualSessionResult.ok) {
        const message =
          manualSessionResult.reason === 'missing'
            ? 'Authentication required'
            : manualSessionResult.reason === 'expired'
            ? 'Session expired'
            : 'Invalid session';

        await reply.code(401).send({
          success: false,
          message
        });
        return;
      }

      const manualUser = getManualAuthUser();
      (request as any).user = manualUser;
      (request as any).tokenPayload = {
        userId: manualUser.id,
        username: manualUser.username,
        email: manualUser.email,
        role: manualUser.role,
        exp: Math.floor(manualSessionResult.session.expiresAt / 1000)
      };
      return;
    }

    const authHeader = request.headers.authorization;
    const cookieToken = (request as any).cookies?.auth_token;
    const token =
      authHeader && authHeader.startsWith('Bearer ')
        ? authHeader.substring(7)
        : typeof cookieToken === 'string' && cookieToken.trim()
        ? cookieToken.trim()
        : null;

    if (!token) {
      throw new UnauthorizedError('Missing or invalid authorization header');
    }

    // Validate token
    const payload = jwtService.validateToken(token);

    // Get full user from database
    const user = await authService.validateToken(request.server, token);

    // Attach user to request
    (request as any).user = user;
    (request as any).tokenPayload = payload;

    logger.debug(`Authenticated user: ${user.username}`);
  } catch (error) {
    if (error instanceof UnauthorizedError) {
      throw error;
    }
    logger.error('Auth middleware error:', error);
    throw new UnauthorizedError('Authentication failed');
  }
}

/**
 * Optional authentication middleware
 * Attaches user if token is present, but doesn't require it
 */
export async function optionalAuthMiddleware(
  request: FastifyRequest,
  _reply: FastifyReply
): Promise<void> {
  try {
    const headers = request.headers as Record<string, unknown>;

    if (hasRoomEnrollmentHeaders(headers) && isValidRoomEnrollmentHeaders(headers)) {
      const roomEnrollment = await getRoomEnrollmentContext(request.server.pg as any, headers);

      if (roomEnrollment) {
        (request as any).user = roomEnrollment.user;
        (request as any).roomEnrollment = roomEnrollment;
        (request as any).tokenPayload = {
          userId: roomEnrollment.user.id,
          username: roomEnrollment.user.username,
          email: roomEnrollment.user.email,
          role: roomEnrollment.user.role,
          exp: Math.floor(Date.now() / 1000) + 3600
        };
        return;
      }
    }

    const authHeader = request.headers.authorization;
    const cookieToken = (request as any).cookies?.auth_token;
    const token =
      authHeader && authHeader.startsWith('Bearer ')
        ? authHeader.substring(7)
        : typeof cookieToken === 'string' && cookieToken.trim()
        ? cookieToken.trim()
        : null;

    if (token) {

      try {
        const payload = jwtService.validateToken(token);
        const user = await authService.validateToken(request.server, token);

        (request as any).user = user;
        (request as any).tokenPayload = payload;

        logger.debug(`Optionally authenticated user: ${user.username}`);
      } catch (error) {
        // Token is invalid, but that's okay for optional auth
        logger.debug('Optional auth token invalid, continuing without user');
      }
    }
  } catch (error) {
    logger.debug('Optional auth middleware error, continuing without user');
  }
}

/**
 * Role-based authorization middleware factory
 * Checks if user has required role
 */
export function requireRole(...allowedRoles: string[]) {
  return async function (request: FastifyRequest, _reply: FastifyReply): Promise<void> {
    const user = (request as any).user;

    if (!user) {
      throw new UnauthorizedError('Authentication required');
    }

    if (!allowedRoles.includes(user.role)) {
      throw new UnauthorizedError('Insufficient permissions');
    }

    logger.debug(`User ${user.username} authorized for roles: ${allowedRoles.join(', ')}`);
  };
}

/**
 * Require teacher role middleware
 */
export const requireTeacher = requireRole('teacher');

/**
 * Require student role middleware
 */
export const requireStudent = requireRole('student');

